/**
 * Fetch report rows based on POST filters
 *
 * Accepted $_POST keys:
 *  - status      : string|array
 *  - category    : string|array
 *  - start_date  : Y-m-d
 *  - end_date    : Y-m-d
 */
function fetchReportRows(PDO $pdo): array
{
    $sql = "
        SELECT
            o.id,
            o.order_number,
            o.status,
            o.category_id,
            c.name          AS category_name,
            o.total_amount,
            o.created_at
        FROM orders o
        LEFT JOIN categories c ON c.id = o.category_id
        WHERE 1
    ";

    $params  = [];
    $clauses = [];

    // Status filter
    if (isset($_POST['status']) && $_POST['status'] !== '') {
        $status = $_POST['status'];
        if (is_array($status)) {
            $placeholders = [];
            foreach ($status as $i => $s) {
                $ph               = ":status_$i";
                $placeholders[]   = $ph;
                $params[$ph]      = $s;
            }
            $clauses[] = 'o.status IN (' . implode(',', $placeholders) . ')';
        } else {
            $clauses[]        = 'o.status = :status';
            $params[':status'] = $status;
        }
    }

    // Category filter
    if (isset($_POST['category']) && $_POST['category'] !== '') {
        $category = $_POST['category'];
        if (is_array($category)) {
            $placeholders = [];
            foreach ($category as $i => $c) {
                $ph                = ":category_$i";
                $placeholders[]    = $ph;
                $params[$ph]       = $c;
            }
            $clauses[] = 'o.category_id IN (' . implode(',', $placeholders) . ')';
        } else {
            $clauses[]           = 'o.category_id = :category';
            $params[':category'] = $category;
        }
    }

    // Date range filter
    $start = $_POST['start_date'] ?? null;
    $end   = $_POST['end_date']   ?? null;

    if ($start && $end) {
        $clauses[]            = 'DATE(o.created_at) BETWEEN :start AND :end';
        $params[':start']      = $start;
        $params[':end']        = $end;
    } elseif ($start) {
        $clauses[]            = 'DATE(o.created_at) >= :start';
        $params[':start']      = $start;
    } elseif ($end) {
        $clauses[]            = 'DATE(o.created_at) <= :end';
        $params[':end']        = $end;
    }

    // Append dynamic clauses
    if ($clauses) {
        $sql .= ' AND ' . implode(' AND ', $clauses);
    }

    // Order results
    $sql .= ' ORDER BY o.created_at DESC';

    $stmt = $pdo->prepare($sql);

    foreach ($params as $key => $val) {
        $stmt->bindValue($key, $val);
    }

    $stmt->execute();

    return $stmt->fetchAll();
}

